const allItems = $input.all();

const results = allItems.map(item => {
  const output = item.json.answer ?? '';
  const firstLine = output.split('\n')[0].trim();

  let tagsPart = firstLine;
  let customerMessage = output;

  // Nếu có tag hợp lệ
  if (firstLine.startsWith('[')) {
    tagsPart = firstLine;
    customerMessage = output.split('\n').slice(1).join('\n').trim();
  } else {
    // fallback
    tagsPart = '[GENERAL]';
  }

  const parts = tagsPart.split('|').map(p => p.trim());

  const convId = $('Webhook').first().json.body?.conversation?.id
              ?? $('Webhook').first().json.body?.id
              ?? '';

  // Time VN
  const now = new Date();
  const vnTime = new Date(now.getTime() + 7 * 60 * 60 * 1000);
  const timestamp = vnTime.toISOString()
                          .replace('T', ' ')
                          .replace(/\.\d+Z$/, '');

  const tag = parts[0] ?? 'UNKNOWN';

  let check_in = '';
  let check_out = '';
  let room_type = '';
  let room = '';
  let service_type = '';
  let detail = '';
  let name = '';
  let phone = '';
  let email = '';
  let reason = '';

  if (tag === '[BOOK]') {
    check_in = parts[1] ?? '';
    check_out = parts[2] ?? '';
    room_type = parts[3] ?? '';
  } 
  else if (tag === '[CONFIRM]') {
    check_in = parts[1] ?? '';
    check_out = parts[2] ?? '';
    room_type = parts[3] ?? '';
    name = parts[4] ?? '';
    phone = parts[5] ?? '';
    email = parts[6] ?? '';
  } 
  else if (tag === '[SERVICE]') {
    room = parts[1] ?? '';
    service_type = parts[2] ?? '';
    detail = parts[3] ?? '';
  } 
  else if (tag === '[HELP]') {
    room = parts[1] ?? '';
    detail = parts[2] ?? '';
  } 
  else if (tag === '[CANCEL]') {
    phone = parts[1] ?? '';
    reason = parts[2] ?? '';
  } 
  else {
    detail = parts.slice(1).join(' ');
  }

  return {
    json: {
      timestamp,
      conversation_id: convId,
      tag,
      check_in,
      check_out,
      room_type,
      room,
      service_type,
      detail,
      name,
      phone,
      email,
      reason,
      status: 'Mới',
      output,
      customer_message: customerMessage,
      property_id: item.json.property_id ?? ''
    }
  };
});

return results;
